#include "elgamal.h"

using namespace NTL;
using namespace std;

void ElgamalGen(ElgamalPublicKey &pk, ElgamalSecretKey &sk, int sk_len) {
    NTL::ZZ p, q;

    p = NTL::conv<NTL::ZZ>("");
    q = NTL::conv<NTL::ZZ>("");

    NTL::mul(pk.N, p, q);
    NTL::mul(pk.N2, pk.N, pk.N);

    NTL::RandomBnd(pk.g, pk.N2);
    while (NTL::Jacobi(pk.g, pk.N) != 1) {
        NTL::RandomBnd(pk.g, pk.N2);
    }

    NTL::add(pk.f, pk.N, 1);

    NTL::RandomBits(sk, sk_len);
    NTL::PowerMod(pk.h, pk.g, sk, pk.N2);
}

void ElgamalEnc(ElgamalCiphertext &ct, const ElgamalPublicKey &pk, const NTL::ZZ &x) {
    NTL::ZZ r;
    NTL::RandomBnd(r, pk.N);

    NTL::PowerMod(ct[0], pk.g, r, pk.N2);
    NTL::PowerMod(ct[1], pk.h, r, pk.N2);
    NTL::MulMod(ct[1], ct[1], 1 + pk.N * x, pk.N2);
}

void ElgamalSkEnc(ElgamalCiphertext &ct, const ElgamalPublicKey &pk, const NTL::ZZ &x) {
    NTL::ZZ r;
    NTL::RandomBnd(r, pk.N);

    NTL::PowerMod(ct[0], pk.g, r, pk.N2);
    NTL::MulMod(ct[0], ct[0], 1 - pk.N * x, pk.N2);
    NTL::PowerMod(ct[1], pk.h, r, pk.N2);
}

void ElgamalDec(NTL::ZZ &x, const ElgamalPublicKey &pk, const ElgamalSecretKey &sk,
                const ElgamalCiphertext &ct) {
    NTL::ZZ temp;
    NTL::PowerMod(temp, ct[0], -sk, pk.N2);
    NTL::MulMod(temp, ct[1], temp, pk.N2);

    NTL::sub(temp, temp, 1);
    NTL::div(x, temp, pk.N);
}
